// ===== 安全获取输入数据 =====
const inputData = $input.item.json || {};
const htmlContent = (inputData["Body Content"] || '').toString().trim();
const rawEmailSubject = (inputData["邮件主题"] || '').toString().trim();
const receiveTime = (inputData["Received Time"] || '').toString().trim();
const messageId = (inputData["Message ID"] || '').toString().trim();
const rowNumber = (inputData["Row Number"] || '').toString();

// ===== 辅助函数 =====

/**
 * 安全提取表格字段值
 * @param {string} html - HTML内容
 * @param {string} fieldName - 字段名
 * @returns {string} 提取的值，失败返回空字符串
 */
function extractField(html, fieldName) {
  if (!html || !fieldName) return '';

  try {
    // 转义正则特殊字符
    const escapedFieldName = fieldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

    const patterns = [
      new RegExp(`<th[^>]*>\\s*${escapedFieldName}:?\\s*</th>\\s*<td[^>]*>([^<]*)</td>`, 'i'),
      new RegExp(`<th[^>]*>\\s*${escapedFieldName}:?\\s*</th>\\s*</tr>\\s*<tr>\\s*<td[^>]*>([^<]*)</td>`, 'i'),
    ];

    for (const pattern of patterns) {
      const match = html.match(pattern);
      if (match && match[1]) {
        const value = match[1].trim();
        // 过滤无效值
        if (value && value.toLowerCase() !== 'null' && value !== 'undefined') {
          return value;
        }
      }
    }
  } catch (error) {
    console.log(`提取字段 "${fieldName}" 失败:`, error.message);
  }

  return '';
}

/**
 * 安全提取反馈正文（支持两种格式）
 * @param {string} html - HTML内容
 * @returns {string} 反馈正文
 */
function extractFeedbackContent(html) {
  if (!html) return '';

  try {
    // 格式1: Suggestions, opinions and questions:
    let match = html.match(/Suggestions,?\s*opinions\s*and\s*questions:?\s*<\/th>\s*<\/tr>\s*<tr>\s*<td[^>]*>([\s\S]*?)<\/td>/i);
    if (match && match[1]) {
      const content = match[1].replace(/<[^>]*>/g, '').trim();
      if (content) return content;
    }

    // 格式2: Detailed Description of the Problem:
    match = html.match(/Detailed\s*Description\s*of\s*the\s*Problem:?\s*<\/th>\s*<\/tr>\s*<tr>\s*<td[^>]*>([\s\S]*?)<\/td>/i);
    if (match && match[1]) {
      const content = match[1].replace(/<[^>]*>/g, '').trim();
      if (content) return content;
    }

    // 备用：匹配colspan="2"的内容
    match = html.match(/<td\s+colspan=["']?2["']?[^>]*>([\s\S]*?)<\/td>/i);
    if (match && match[1]) {
      const content = match[1].replace(/<[^>]*>/g, '').trim();
      // 排除标题行
      if (content && !content.includes('Suggestions') && !content.includes('Description')) {
        return content;
      }
    }
  } catch (error) {
    console.log('提取反馈正文失败:', error.message);
  }

  return '';
}

/**
 * 判断反馈格式类型
 * @param {string} html - HTML内容
 * @returns {string} 格式类型
 */
function getFeedbackFormat(html) {
  if (!html) return 'unknown';

  if (html.includes('Suggestions, opinions and questions') || 
      html.includes('Suggestions,opinions and questions')) {
    return 'suggestions';
  } else if (html.includes('Detailed Description of the Problem')) {
    return 'detailed';
  }
  return 'unknown';
}

/**
 * 清理并验证字段值
 * @param {string} value - 原始值
 * @param {string} defaultValue - 默认值
 * @returns {string} 清理后的值
 */
function cleanValue(value, defaultValue = '') {
  if (value === null || value === undefined) return defaultValue;

  const strValue = String(value).trim();

  // 过滤无效值
  const invalidValues = ['null', 'undefined', 'N/A', 'n/a', 'NA', '-'];
  if (invalidValues.includes(strValue.toLowerCase()) || strValue === '') {
    return defaultValue;
  }

  return strValue;
}

/**
 * 尝试多个字段名提取值
 * @param {string} html - HTML内容
 * @param {string[]} fieldNames - 字段名数组
 * @returns {string} 提取的值
 */
function extractFieldMultiple(html, fieldNames) {
  for (const fieldName of fieldNames) {
    const value = extractField(html, fieldName);
    if (value) return value;
  }
  return '';
}

// ===== 主逻辑 =====

let parsed = {};

try {
  // 检查是否有有效的HTML内容
  const hasValidHtml = htmlContent && htmlContent.includes('<') && htmlContent.includes('>');

  if (!hasValidHtml) {
    console.log('警告: HTML内容为空或无效');
  }

  parsed = {
    // ----- 来自Google Sheet的原始数据 -----
    "Received Date": cleanValue(receiveTime),
    "Original Email": htmlContent || '',  // 保留原始HTML，即使为空
    "Message ID": cleanValue(messageId),
    "Row Number": cleanValue(rowNumber),
    "Email Subject": cleanValue(rawEmailSubject),  // ← 新增这一行

    // ----- 解析的反馈信息 -----
    "feedbackFormat": getFeedbackFormat(htmlContent),
    "Original Feedback": extractFeedbackContent(htmlContent),
    "Feedback Category": extractFieldMultiple(htmlContent, ['Feeback Category', 'Feedback Category']),
    "Feedback Type": extractFieldMultiple(htmlContent, ['Feeback Type', 'Feedback Type']),

    // ----- 用户信息 -----
    "User Email": cleanValue(extractField(htmlContent, 'Email')),
    "User ID 2": cleanValue(extractField(htmlContent, 'User ID 2')),
    "User Name": cleanValue(extractField(htmlContent, 'Name')),
    "Country": extractFieldMultiple(htmlContent, ['Country', 'Location']),
    "Region": cleanValue(extractField(htmlContent, 'Area')),

    // ----- 设备信息 -----
    "Device Model": extractFieldMultiple(htmlContent, [
      "What's the model/version number of your device",
      'Model Number',
      'Model Type'
    ]),
    "Hardware Version": cleanValue(extractField(htmlContent, 'Hardware Version')),
    "Firmware Version": extractFieldMultiple(htmlContent, ['Firmware Version', 'Firmware']),

    // ----- App和手机信息 -----
    "App Version": cleanValue(extractField(htmlContent, 'App Version')),
    "Mobile OS": cleanValue(extractField(htmlContent, 'Mobile OS Version')),
    "Phone Model": cleanValue(extractField(htmlContent, 'Mobile Type')),

    // ----- 解析状态 -----
    "_parseSuccess": hasValidHtml && extractFeedbackContent(htmlContent) !== '',
    "_parseTime": new Date().toISOString(),
  };

  // 验证关键字段
  if (!parsed["Original Feedback"]) {
    console.log('警告: 未能提取到反馈正文');
    parsed._parseSuccess = false;
  }

} catch (error) {
  console.log('解析邮件内容时发生错误:', error.message);

  // 返回基本数据，标记解析失败
  parsed = {
    "Received Date": cleanValue(receiveTime),
    "Original Email": htmlContent || '',
    "Message ID": cleanValue(messageId),
    "Row Number": cleanValue(rowNumber),
    "Email Subject": cleanValue(rawEmailSubject),  // ← 新增这一行
    "Original Feedback": '',
    "Feedback Category": '',
    "Feedback Type": '',
    "User Email": '',
    "User ID 2": '',
    "User Name": '',
    "Country": '',
    "Region": '',
    "Device Model": '',
    "Hardware Version": '',
    "Firmware Version": '',
    "App Version": '',
    "Mobile OS": '',
    "Phone Model": '',
    "feedbackFormat": 'error',
    "_parseSuccess": false,
    "_parseError": error.message,
    "_parseTime": new Date().toISOString(),
  };
}

return parsed;

const items = $input.all();
const seen = new Map(); // 存储 dedupeKey -> {index, time}
const unique = [];

// 简单的字符串哈希函数
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString();
}

// 从 HTML 中提取关键内容
function extractFeedbackText(html) {
  const feedbackMatch = html.match(/Suggestions, opinions and questions:<\/th><\/tr><tr><td[^>]*>([^<]*)/);
  const feedback = feedbackMatch ? feedbackMatch[1].trim() : '';

  const emailMatch = html.match(/Email:<\/th><td[^>]*>([^<]*)/);
  const email = emailMatch ? emailMatch[1].trim() : '';

  const userId2Match = html.match(/User ID 2:<\/th><td[^>]*>([^<]*)/);
  const userId2 = userId2Match ? userId2Match[1].trim() : '';

  return `${feedback}_${email}_${userId2}`;
}

// 第一轮：找出每个去重键对应的最晚时间记录
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const subject = item.json['邮件主题'] || '';
  const html = item.json['Body Content'] || '';
  const time = item.json['Received Time'] || '';

  const feedbackText = extractFeedbackText(html);
  const dedupeKey = `${subject}_${simpleHash(feedbackText)}`;

  if (!seen.has(dedupeKey)) {
    seen.set(dedupeKey, { index: i, time: time });
  } else {
    // 比较时间，保留更晚的
    if (time > seen.get(dedupeKey).time) {
      seen.set(dedupeKey, { index: i, time: time });
    }
  }
}

// 第二轮：收集去重后的记录
const keepIndexes = new Set([...seen.values()].map(v => v.index));
for (let i = 0; i < items.length; i++) {
  if (keepIndexes.has(i)) {
    unique.push(items[i]);
  }
}

return unique;

const items = $input.all();

const groups = new Map();

for (const item of items) {
  const data = item.json;

  // 直接使用已解析的字段
  const userId2 = (data['User ID 2'] || '').trim().toLowerCase();
  const email = (data['User Email'] || '').trim().toLowerCase();
  const userName = (data['User Name'] || '').trim().toLowerCase();
  const messageId = data['Message ID'] || String(Math.random());

  // 确定用户标识
  let userId = '';
  if (userId2 && userId2 !== 'null' && userId2.length > 0) {
    userId = userId2;
  } else if (email && email !== 'null' && email.length > 0) {
    userId = email;
  } else if (userName && userName !== 'null' && userName.length > 0) {
    userId = userName;
  } else {
    userId = 'unknown_' + messageId;
  }

  if (!groups.has(userId)) {
    groups.set(userId, []);
  }
  groups.get(userId).push(data);
}

const result = [];
for (const [userId, feedbacks] of groups) {
  const isUnknown = userId.startsWith('unknown_');

  // 构建 LLM 输入文本
  const llmInput = feedbacks.map((f, i) => 
    '[反馈' + (i + 1) + '] 时间: ' + f['Received Date'] + '\n主题: ' + f['邮件主题'] + '\n内容: ' + f['Original Feedback']
  ).join('\n\n---\n\n');

  result.push({
    json: {
      userId: userId,
      count: feedbacks.length,
      needDedup: !isUnknown && feedbacks.length > 1,
      feedbacks: feedbacks,
      llmInput: llmInput
    }
  });
}

return result;

const group = $('If').item.json;
const response = $json;

let result = { isDuplicate: false, keepIndex: -1 };

try {
  // Message a Model 节点的输出格式
  let content = response.message?.content || response.content || response.text || '';

  // 如果 content 已经是对象，直接使用
  if (typeof content === 'object') {
    result = content;
  } else if (typeof content === 'string') {
    // 如果是字符串，提取 JSON
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      result = JSON.parse(jsonMatch[0]);
    }
  }
} catch (e) {
  // 解析失败，保留所有
}

const feedbacks = group.feedbacks || [];

if (result.isDuplicate && result.keepIndex >= 0 && result.keepIndex < feedbacks.length) {
  const sorted = [...feedbacks].sort((a, b) => 
    (a['Received Date'] || '').localeCompare(b['Received Date'] || '')
  );
  return [{ json: sorted[result.keepIndex] }];
} else {
  return feedbacks.map(f => ({ json: f }));
}

