const data = $input.item.json;

// 获取 AI 分析结果
let aiResult = {};

// AI 结果可能在 message.content 或 message_2.content 中
if (data?.message?.content) {
  aiResult = data.message.content;
} else if (data?.message_2?.content) {
  aiResult = data.message_2.content;
}

// 辅助函数：优先获取原字段，没有则获取带 _1 后缀的字段
function getField(obj, fieldName, defaultValue) {
  if (!obj) return defaultValue;

  // 优先尝试原字段名
  let value = obj[fieldName];
  if (value !== null && value !== undefined && value !== '' && value !== 'null') {
    return value;
  }

  // 尝试带 _1 后缀的字段
  value = obj[fieldName + '_1'];
  if (value !== null && value !== undefined && value !== '' && value !== 'null') {
    return value;
  }

  // 尝试带 _2 后缀的字段
  value = obj[fieldName + '_2'];
  if (value !== null && value !== undefined && value !== '' && value !== 'null') {
    return value;
  }

  return defaultValue;
}

// 合并输出
const mergedData = {
  // ----- Original Email字段 -----
  "Received Date": getField(data, 'Received Date', ''),
  "Original Email": getField(data, 'Original Email', ''),
  "Email Subject": getField(data, 'Email Subject', ''),
  "Original Feedback": getField(data, 'Original Feedback', ''),
  "Feedback Category": getField(data, 'Feedback Category', ''),
  "Feedback Type": getField(data, 'Feedback Type', ''),
  "User Email": getField(data, 'User Email', ''),
  "User ID 2": getField(data, 'User ID 2', ''),
  "User Name": getField(data, 'User Name', ''),
  "Country": getField(data, 'Country', ''),
  "Region": getField(data, 'Region', ''),
  "Device Model": getField(data, 'Device Model', ''),
  "Hardware Version": getField(data, 'Hardware Version', ''),
  "Firmware Version": getField(data, 'Firmware Version', ''),
  "App Version": getField(data, 'App Version', ''),
  "Mobile OS": getField(data, 'Mobile OS', ''),
  "Phone Model": getField(data, 'Phone Model', ''),
  "Message ID": getField(data, 'Message ID', ''),
  "Row Number": getField(data, 'Row Number', ''),
  "feedbackFormat": getField(data, 'feedbackFormat', ''),

  // ----- AI 分析字段 -----
  "Issue Summary": aiResult.summary || '无法识别',
  "Translated Text": aiResult.translatedFeedback || '',
  "Sentiment": aiResult.sentiment || 'Neutral',
  "Is Urgent": aiResult.isUrgent === true,
  "Feedback Type详情": aiResult.feedbackCategory || '其他',
};

return mergedData;
